const config = $node["Set | Import Config"].json;

return [
  {
    json: {
      source_file_name: config.source_file_name,
      source_file_id: config.source_file_id,
      record_type: config.record_type,
      schema_version: config.schema_version,
      inferred_year: Number(config.inferred_year || 2026),
      extracted_item_count: items.length,
      first_item: items[0]?.json || null,
      first_5_items: items.slice(0, 5).map(item => item.json)
    }
  }
];

const output = items[0].json;

if (!output.job) {
  throw new Error(
    'Debug Summary expected output.job. Make sure this node is connected directly after Normalize + Validate XLSX.'
  );
}

return [
  {
    json: {
      ...output,
      debug_summary: {
        success: true,
        import_job_id: output.job.import_job_id,
        status: output.job.status,
        clean_record_count: output.job.clean_record_count,
        rejected_row_count: output.job.rejected_row_count,
        issue_count: output.job.issue_count,
        warning_count: output.job.warning_count,
        error_count: output.job.error_count,
        first_clean_record: output.records?.[0] || null,
        rejected_rows_sample: output.rejected_rows?.slice(0, 5) || [],
        issues_sample: output.issues?.slice(0, 10) || [],
        message: 'Transformation completed. No database write performed yet.'
      }
    }
  }
];

const output = items[0].json;

if (!output.job) {
  throw new Error('Missing output.job. Connect this node after Normalize + Validate XLSX or after the pass-through Debug Summary node.');
}

if (!Array.isArray(output.records)) {
  throw new Error('Missing output.records array. The previous node probably removed the full normalized payload.');
}

const cleanRecords = output.records.map(record => ({
  record_type: record.record_type,
  record_category: record.record_category,
  record_subcategory: record.record_subcategory,
  title: record.title,
  start_date: record.start_date,
  end_date: record.end_date,
  month: record.month,
  location: record.location,
  website: record.website,
  entity: record.entity,
  ga: record.ga,
  attendance_format: record.attendance_format,
  sponsoring_level: record.sponsoring_level,
  contact_person: record.contact_person,
  project_owner: record.project_owner,
  status: record.status,
  validation_status: record.validation_status,
  validation_notes: record.validation_notes,
  source_file_name: record.source_file_name,
  source_sheet: record.source_sheet,
  source_row_number: record.source_row_number
}));

const baseName = String(output.job.source_file_name || 'events_import')
  .replace(/\.[^.]+$/, '')
  .replace(/[^\w.-]+/g, '_');

return [
  {
    json: {
      file_type: 'clean_records',
      file_name: `${baseName}_clean_records.json`,
      data: cleanRecords
    }
  },
  {
    json: {
      file_type: 'rejected_rows',
      file_name: `${baseName}_rejected_rows.json`,
      data: output.rejected_rows || []
    }
  },
  {
    json: {
      file_type: 'issues',
      file_name: `${baseName}_import_issues.json`,
      data: output.issues || []
    }
  },
  {
    json: {
      file_type: 'full_import_payload',
      file_name: `${baseName}_full_import_payload.json`,
      data: output
    }
  }
];

const item = items[0].json;

if (item.file_type !== 'clean_records') {
  throw new Error(`Expected file_type "clean_records", received "${item.file_type}".`);
}

if (!Array.isArray(item.data)) {
  throw new Error('Expected item.data to be an array of clean records.');
}

const rows = item.data;

const preferredColumns = [
  'record_type',
  'record_category',
  'record_subcategory',
  'title',
  'start_date',
  'end_date',
  'month',
  'location',
  'website',
  'entity',
  'ga',
  'attendance_format',
  'sponsoring_level',
  'contact_person',
  'project_owner',
  'status',
  'validation_status',
  'validation_notes',
  'source_file_name',
  'source_sheet',
  'source_row_number'
];

const allColumns = Array.from(
  new Set(rows.flatMap(row => Object.keys(row)))
);

const columns = [
  ...preferredColumns.filter(col => allColumns.includes(col)),
  ...allColumns.filter(col => !preferredColumns.includes(col))
];

function csvEscape(value) {
  if (value === null || value === undefined) return '';

  let s;

  if (typeof value === 'object') {
    s = JSON.stringify(value);
  } else {
    s = String(value);
  }

  if (/[",\n\r]/.test(s)) {
    return `"${s.replace(/"/g, '""')}"`;
  }

  return s;
}

const lines = [];

lines.push(columns.map(csvEscape).join(','));

for (const row of rows) {
  lines.push(columns.map(col => csvEscape(row[col])).join(','));
}

const csv = '\uFEFF' + lines.join('\r\n');

const baseName = String(item.file_name || 'clean_records.json')
  .replace(/\.json$/i, '')
  .replace(/[^\w.-]+/g, '_');

const fileName = `${baseName}.csv`;

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(csv, 'utf8'),
  fileName,
  'text/csv'
);

return [
  {
    json: {
      file_type: 'clean_records_csv',
      file_name: fileName,
      row_count: rows.length,
      column_count: columns.length,
      columns
    },
    binary: {
      data: binaryData
    }
  }
];

const config = $node["Set | Import Config"].json;

if (!items[0].binary?.data) {
  throw new Error('Missing binary.data from Google Drive download.');
}

const sheetNames = String(config.sheet_names_csv || '')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);

if (!sheetNames.length) {
  throw new Error('No sheet names provided in sheet_names_csv.');
}

return sheetNames.map(sheetName => ({
  json: {
    source_sheet: sheetName,
    source_file_id: config.source_file_id,
    source_file_name: config.source_file_name,
    record_type: config.record_type || 'event',
    schema_version: config.schema_version || 'canonical-records-v1',
    inferred_year: Number(config.inferred_year || 2026)
  },
  binary: items[0].binary
}));

const config = $node["Set | Import Config"].json;

const schemaVersion = config.schema_version || 'canonical-records-v1';
const defaultRecordType = config.record_type || 'event';
const inferredYear = Number(config.inferred_year || 2026);
const sourceFileId = config.source_file_id || null;
const sourceFileName = config.source_file_name || 'unknown_xlsx_file';

const importJobId = `imp_${Date.now()}`;

const MONTHS = {
  jan: 'January', january: 'January',
  feb: 'February', february: 'February', febuary: 'February', febiary: 'February',
  mar: 'March', march: 'March',
  apr: 'April', april: 'April',
  may: 'May',
  jun: 'June', june: 'June',
  jul: 'July', july: 'July',
  aug: 'August', august: 'August',
  sep: 'September', sept: 'September', september: 'September',
  oct: 'October', october: 'October',
  nov: 'November', november: 'November',
  dec: 'December', december: 'December',
};

const MONTH_NUM = {
  January: 1,
  February: 2,
  March: 3,
  April: 4,
  May: 5,
  June: 6,
  July: 7,
  August: 8,
  September: 9,
  October: 10,
  November: 11,
  December: 12,
};

function clean(value) {
  if (value === null || value === undefined) return null;

  const s = String(value)
    .replace(/\u00a0/g, ' ')
    .trim()
    .replace(/\s+/g, ' ');

  if (!s) return null;

  const lower = s.toLowerCase();
  if (['-', '—', 'n/a', 'na', 'null', 'undefined'].includes(lower)) {
    return null;
  }

  return s;
}

function norm(value) {
  return String(value ?? '')
    .replace(/\u00a0/g, ' ')
    .trim()
    .toLowerCase()
    .replace(/&/g, ' and ')
    .replace(/[_\-./:;()\[\]]+/g, ' ')
    .replace(/[^\p{L}\p{N}\s?]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function hash(input, length = 16) {
  let h = 2166136261;
  const s = String(input ?? '');

  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }

  const hex = (h >>> 0).toString(16).padStart(8, '0');
  return (hex + hex + hex + hex).slice(0, length);
}

function monthName(value) {
  const s = norm(value);
  if (!s) return null;
  return MONTHS[s] || MONTHS[s.split(' ')[0]] || null;
}

function pad2(n) {
  return String(n).padStart(2, '0');
}

function isoDate(year, month, day) {
  const y = Number(year);
  const m = Number(month);
  const d = Number(day);

  if (!y || !m || !d) return null;

  const date = new Date(Date.UTC(y, m - 1, d));

  if (
    date.getUTCFullYear() !== y ||
    date.getUTCMonth() !== m - 1 ||
    date.getUTCDate() !== d
  ) {
    return null;
  }

  return `${y}-${pad2(m)}-${pad2(d)}`;
}

function excelSerialToIso(value) {
  const n = Number(value);

  if (!Number.isFinite(n)) return null;
  if (n < 1 || n > 80000) return null;

  const ms = Date.UTC(1899, 11, 30) + n * 24 * 60 * 60 * 1000;
  const d = new Date(ms);

  return isoDate(d.getUTCFullYear(), d.getUTCMonth() + 1, d.getUTCDate());
}

function parseYear(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return null;
  return n < 100 ? 2000 + n : n;
}

function parseDate(value, monthContext) {
  const serialDate = excelSerialToIso(value);

  if (serialDate) {
    return {
      date: serialDate,
      warning: null,
      error: null,
    };
  }

  const raw = clean(value);

  if (!raw) {
    return {
      date: null,
      warning: null,
      error: null,
    };
  }

  let m;

  // 2026-01-11
  m = raw.match(/^(\d{4})[-/.](\d{1,2})[-/.](\d{1,2})$/);
  if (m) {
    const date = isoDate(Number(m[1]), Number(m[2]), Number(m[3]));
    if (date) return { date, warning: null, error: null };
  }

  // 11-Jan-26
  m = raw.match(/^(\d{1,2})(?:st|nd|rd|th)?[-\s]([A-Za-z]+)[-\s](\d{2,4})$/i);
  if (m) {
    const mo = monthName(m[2]);
    const date = mo ? isoDate(parseYear(m[3]), MONTH_NUM[mo], Number(m[1])) : null;
    if (date) return { date, warning: null, error: null };
  }

  // 11 Jan 2026
  m = raw.match(/^(\d{1,2})(?:st|nd|rd|th)?\s+([A-Za-z]+)\s+(\d{2,4})$/i);
  if (m) {
    const mo = monthName(m[2]);
    const date = mo ? isoDate(parseYear(m[3]), MONTH_NUM[mo], Number(m[1])) : null;
    if (date) return { date, warning: null, error: null };
  }

  // DD/MM/YYYY or DD-MM-YY
  m = raw.match(/^(\d{1,2})[-/.](\d{1,2})[-/.](\d{2,4})$/);
  if (m) {
    const date = isoDate(parseYear(m[3]), Number(m[2]), Number(m[1]));
    if (date) return { date, warning: null, error: null };
  }

  // 12th, with month inferred
  m = raw.match(/^(\d{1,2})(?:st|nd|rd|th)?$/i);
  if (m && monthContext) {
    const mo = monthName(monthContext);
    const date = mo ? isoDate(inferredYear, MONTH_NUM[mo], Number(m[1])) : null;

    if (date) {
      return {
        date,
        warning: `Date "${raw}" had no month/year. Inferred ${mo} ${inferredYear}.`,
        error: null,
      };
    }
  }

  return {
    date: null,
    warning: null,
    error: `Could not parse date "${raw}".`,
  };
}

function parseBool(value) {
  const s = norm(value);
  if (!s) return null;

  if (['yes', 'y', 'true', '1', 'ja'].includes(s)) return true;
  if (['no', 'n', 'false', '0', 'nein'].includes(s)) return false;

  return null;
}

function normalizeUrl(value) {
  const s = clean(value);
  if (!s) return null;

  if (/^https?:\/\//i.test(s)) return s;

  if (/^[\w.-]+\.[a-z]{2,}(\/.*)?$/i.test(s)) {
    return `https://${s}`;
  }

  return s;
}

function fieldFromHeader(header) {
  const h = norm(header);

  const aliases = {
    month: [
      'month'
    ],

    start_date: [
      'event start date',
      'start date',
      'event date',
      'date',
      'from'
    ],

    end_date: [
      'event end date',
      'end date',
      'to'
    ],

    title: [
      'event name',
      'title',
      'name',
      'event',
      'activity name'
    ],

    location: [
      'location',
      'venue',
      'place',
      'city'
    ],

    ga: [
      'ga',
      'ga?',
      'general availability'
    ],

    website: [
      'website',
      'web site',
      'url',
      'link'
    ],

    attendance_sponsoring_combined: [
      'type of attendance and sponsering',
      'type of attendance and sponsoring',
      'attendance and sponsoring',
      'attendance sponsoring',
      'attendance/sponsoring'
    ],

    attendance_format: [
      'attendance format',
      'type of attendance',
      'attendance',
      'attendance type'
    ],

    sponsoring_level: [
      'sponsering',
      'sponsoring',
      'sponsoring level',
      'sponsorship level',
      'sponsorship'
    ],

    entity: [
      'entity',
      'company',
      'organization',
      'organisation',
      'business unit'
    ],

    contact_person: [
      'comments',
      'comment',
      'contact person',
      'contact',
      'responsible contact'
    ],

    project_owner: [
      'project owner',
      'owner',
      'project lead',
      'responsible'
    ],

    status: [
      'status',
      'state',
      'completed postponed cancelled',
      'completed postponed canceled'
    ],

    requirements: [
      'requirements',
      'requirement'
    ],

    record_category: [
      'category',
      'event category',
      'type',
      'event type'
    ],
  };

  for (const [field, list] of Object.entries(aliases)) {
    if (list.map(norm).includes(h)) return field;
  }

  return null;
}

function buildColumnMapFromHeaderValues(row) {
  const columnMap = {};

  for (const [key, value] of Object.entries(row)) {
    if (key.startsWith('_n8n_')) continue;

    const label = clean(value) || key;
    const field = fieldFromHeader(label);

    if (field && columnMap[field] === undefined) {
      columnMap[field] = key;
    }
  }

  return columnMap;
}

function buildColumnMapFromKeys(row) {
  const columnMap = {};

  for (const key of Object.keys(row)) {
    if (key.startsWith('_n8n_')) continue;

    const field = fieldFromHeader(key);

    if (field && columnMap[field] === undefined) {
      columnMap[field] = key;
    }
  }

  return columnMap;
}

function countMapFields(map) {
  return Object.keys(map || {}).length;
}

function mapSignature(map) {
  return JSON.stringify(Object.keys(map || {}).sort());
}

function hasCoreKeyBasedFields(map) {
  return Boolean(
    map &&
    map.start_date !== undefined &&
    (
      map.title !== undefined ||
      map.website !== undefined ||
      map.location !== undefined
    )
  );
}

function mapsAreCompatible(currentMap, nextMap) {
  if (!currentMap || !nextMap) return false;

  const importantFields = [
    'start_date',
    'title',
    'location',
    'website',
    'attendance_sponsoring_combined',
    'entity',
    'contact_person',
    'project_owner'
  ];

  const sharedImportantFields = importantFields.filter(field =>
    currentMap[field] !== undefined && nextMap[field] !== undefined
  );

  return sharedImportantFields.length >= 2;
}

function isHeaderLikeRow(row) {
  const values = Object.values(row).map(clean).filter(Boolean);
  if (values.length < 2) return false;

  const mappedCount = values.filter(value => fieldFromHeader(value)).length;

  return mappedCount >= 2;
}

function detectSectionName(row, fallbackIndex, source) {
  const keys = Object.keys(row).map(clean).filter(Boolean);
  const values = Object.values(row).map(clean).filter(Boolean);

  const keyText = keys.join(' | ');
  const valueText = values.join(' | ');
  const combined = `${keyText} | ${valueText}`;

  if (/external/i.test(combined)) {
    return 'External | International & National Events';
  }

  if (/delegates/i.test(combined) || /internal events/i.test(combined) || /visits/i.test(combined)) {
    return 'Delegates, Internal Events and Visits';
  }

  const keyNames = keys.map(norm);

  if (
    keyNames.includes('event date') &&
    (keyNames.includes('title') || keyNames.includes('name')) &&
    keyNames.includes('website')
  ) {
    return 'Seminars and Training';
  }

  if (source === 'keys' && keys.some(key => fieldFromHeader(key))) {
    return 'Seminars and Training';
  }

  return `Section ${fallbackIndex}`;
}

function splitAttendanceAndSponsoring(combined, attendanceRaw, sponsoringRaw) {
  let attendance = clean(attendanceRaw);
  let sponsoring = clean(sponsoringRaw);

  const c = clean(combined);

  if (!c) {
    return {
      attendance_format: attendance,
      sponsoring_level: sponsoring,
    };
  }

  const parts = c
    .split(/\s*\+\s*|\s*\/\s*|\s*,\s*/)
    .map(clean)
    .filter(Boolean);

  const sponsorWords = [
    'sponsor',
    'sponsoring',
    'sponsering',
    'sponsorship',
    'gold',
    'silver',
    'bronze',
    'platinum',
  ];

  const attendanceParts = [];
  const sponsoringParts = [];

  for (const part of parts.length ? parts : [c]) {
    const n = norm(part);

    if (sponsorWords.some(word => n.includes(word))) {
      sponsoringParts.push(part.replace(/sponsering/ig, 'Sponsoring'));
    } else {
      attendanceParts.push(part);
    }
  }

  if (!attendance && attendanceParts.length) {
    attendance = attendanceParts.join(' + ');
  }

  if (!sponsoring && sponsoringParts.length) {
    sponsoring = sponsoringParts.join(' + ');
  }

  if (!attendance && !sponsoring && c) {
    attendance = c;
  }

  return {
    attendance_format: attendance,
    sponsoring_level: sponsoring,
  };
}

function getMappedValue(row, columnMap, field) {
  if (!columnMap) return null;

  const key = columnMap[field];
  return key === undefined ? null : row[key];
}

function getMappedValueFromEitherMap(row, primaryMap, fallbackMap, field) {
  const primary = getMappedValue(row, primaryMap, field);

  if (clean(primary) !== null) {
    return primary;
  }

  return getMappedValue(row, fallbackMap, field);
}

function currentMapCanReadRow(row, currentMap) {
  if (!currentMap) return false;

  return Boolean(
    clean(getMappedValue(row, currentMap, 'title')) ||
    clean(getMappedValue(row, currentMap, 'start_date')) ||
    clean(getMappedValue(row, currentMap, 'website')) ||
    clean(getMappedValue(row, currentMap, 'location'))
  );
}

function keyMapCanReadRow(row, keyMap) {
  if (!keyMap) return false;

  return Boolean(
    clean(getMappedValue(row, keyMap, 'title')) ||
    clean(getMappedValue(row, keyMap, 'start_date')) ||
    clean(getMappedValue(row, keyMap, 'website')) ||
    clean(getMappedValue(row, keyMap, 'location'))
  );
}

function findNextExplicitMonth(startIndex, columnMap) {
  for (let j = startIndex; j < items.length; j++) {
    const futureRow = items[j].json;

    const futureValueMap = buildColumnMapFromHeaderValues(futureRow);
    const futureKeyMap = buildColumnMapFromKeys(futureRow);

    const futureLooksLikeHeader = isHeaderLikeRow(futureRow);

    // A real value-based header means a new section has started.
    if (futureLooksLikeHeader && countMapFields(futureValueMap) >= 2) {
      return null;
    }

    // If keys change but are still compatible with the current section,
    // keep scanning. This matters for Seminars rows where Month/Name
    // appear only on some rows.
    if (
      countMapFields(futureKeyMap) >= 2 &&
      !mapsAreCompatible(columnMap, futureKeyMap) &&
      hasCoreKeyBasedFields(futureKeyMap)
    ) {
      return null;
    }

    const rawMonth =
      getMappedValue(futureRow, columnMap, 'month') ??
      getMappedValue(futureRow, futureKeyMap, 'month');

    const explicitMonth = monthName(rawMonth);

    if (explicitMonth) {
      return explicitMonth;
    }
  }

  return null;
}

function buildRawRow(row, headerRow) {
  const raw = {};

  for (const [key, value] of Object.entries(row)) {
    if (key.startsWith('_n8n_')) continue;

    if (headerRow) {
      raw[clean(headerRow[key]) || key] = value ?? null;
    } else {
      raw[key] = value ?? null;
    }
  }

  return raw;
}

function buildExtraFields(row, columnMap, headerRow) {
  const usedKeys = new Set(Object.values(columnMap || {}));
  const extra = {};

  for (const [key, value] of Object.entries(row)) {
    if (key.startsWith('_n8n_')) continue;
    if (usedKeys.has(key)) continue;

    const label = headerRow ? clean(headerRow[key]) || key : key;
    const cleanedValue = clean(value);

    if (cleanedValue !== null) {
      extra[label] = cleanedValue;
    }
  }

  return extra;
}

function addIssue(issues, base, severity, issueCode, fieldName, message, originalValue = null, normalizedValue = null) {
  issues.push({
    import_job_id: importJobId,
    severity,
    issue_code: issueCode,
    field_name: fieldName,
    source_file_id: sourceFileId,
    source_file_name: sourceFileName,
    source_sheet: base.source_sheet,
    source_row_number: base.source_row_number,
    original_value: originalValue === null || originalValue === undefined ? null : String(originalValue),
    normalized_value: normalizedValue === null || normalizedValue === undefined ? null : String(normalizedValue),
    message,
  });
}

const records = [];
const rejected_rows = [];
const issues = [];

let currentSection = null;
let currentColumnMap = null;
let currentHeaderRow = null;
let currentMonth = null;
let currentSectionSignature = null;
let sectionCounter = 0;

for (let i = 0; i < items.length; i++) {
  const row = items[i].json;

  // The Extract From File node skipped the visual title row in this workbook,
  // so this approximates the original Excel row number.
  const sourceRowNumber = i + 2;

  const valueMap = buildColumnMapFromHeaderValues(row);
  const keyMap = buildColumnMapFromKeys(row);

  const valueFieldCount = countMapFields(valueMap);
  const keyFieldCount = countMapFields(keyMap);

  const keySignature = mapSignature(keyMap);
  const currentSignature = currentSectionSignature;

  const rowLooksLikeHeader = isHeaderLikeRow(row);

  const shouldStartValueHeaderSection =
    rowLooksLikeHeader && valueFieldCount >= 2;

  const currentCanReadThisRow = currentMapCanReadRow(row, currentColumnMap);
  const keyMapCanReadThisRow = keyMapCanReadRow(row, keyMap);

  const shouldStartKeyBasedSection =
    keyFieldCount >= 2 &&
    hasCoreKeyBasedFields(keyMap) &&
    (
      !currentColumnMap ||

      // Critical fix:
      // if the previous section map cannot read this row,
      // but the current row's own keys can, this is a new key-based section.
      (
        !currentCanReadThisRow &&
        keyMapCanReadThisRow
      ) ||

      (
        keySignature !== currentSignature &&
        !mapsAreCompatible(currentColumnMap, keyMap)
      )
    );

  if (shouldStartValueHeaderSection) {
    sectionCounter++;

    currentSection = detectSectionName(row, sectionCounter, 'values');
    currentColumnMap = valueMap;
    currentHeaderRow = row;
    currentMonth = null;
    currentSectionSignature = mapSignature(currentColumnMap);

    addIssue(
      issues,
      {
        source_sheet: currentSection,
        source_row_number: sourceRowNumber
      },
      'info',
      'section_header_detected',
      null,
      `Detected section header for "${currentSection}" from row values.`,
      null,
      JSON.stringify(currentColumnMap)
    );

    continue;
  }

  if (shouldStartKeyBasedSection) {
    sectionCounter++;

    currentSection = detectSectionName(row, sectionCounter, 'keys');
    currentColumnMap = keyMap;
    currentHeaderRow = null;
    currentMonth = null;
    currentSectionSignature = mapSignature(currentColumnMap);

    addIssue(
      issues,
      {
        source_sheet: currentSection,
        source_row_number: sourceRowNumber
      },
      'info',
      'section_from_keys_detected',
      null,
      `Detected section "${currentSection}" from extracted JSON keys.`,
      null,
      JSON.stringify(currentColumnMap)
    );
  }

  if (!currentColumnMap) {
    addIssue(
      issues,
      {
        source_sheet: 'Unknown',
        source_row_number: sourceRowNumber
      },
      'warning',
      'row_skipped_no_section',
      null,
      'Skipped row because no section/header had been detected yet.'
    );

    continue;
  }

  const visibleValues = Object.entries(row)
    .filter(([key]) => !key.startsWith('_n8n_'))
    .map(([, value]) => value);

  if (visibleValues.every(value => clean(value) === null)) {
    continue;
  }

  const get = field => getMappedValueFromEitherMap(
    row,
    currentColumnMap,
    keyMap,
    field
  );

  const rawMonth = get('month');
  const explicitMonth = monthName(rawMonth);

  if (explicitMonth) {
    currentMonth = explicitMonth;
  }

  let month = explicitMonth || currentMonth;

  const startRaw = get('start_date');
  const endRaw = get('end_date');

  const startLooksDayOnly =
    clean(startRaw) &&
    /^(\d{1,2})(?:st|nd|rd|th)?$/i.test(clean(startRaw));

  const base = {
    source_sheet: currentSection,
    source_row_number: sourceRowNumber
  };

  if (!month && startLooksDayOnly) {
    const nextMonth = findNextExplicitMonth(i + 1, currentColumnMap);

    if (nextMonth) {
      month = nextMonth;
      currentMonth = nextMonth;

      addIssue(
        issues,
        base,
        'warning',
        'month_backfilled_from_next_row',
        'month',
        `Blank month backfilled from a later row as ${nextMonth}.`,
        rawMonth,
        nextMonth
      );
    }
  }

  if (!explicitMonth && month) {
    addIssue(
      issues,
      base,
      'warning',
      'month_filled_down',
      'month',
      `Blank month filled down as ${month}.`,
      rawMonth,
      month
    );
  }

  const startParsed = parseDate(startRaw, month);
  const endParsed = parseDate(endRaw, month);

  if (startParsed.warning) {
    addIssue(
      issues,
      base,
      'warning',
      'inferred_start_date',
      'start_date',
      startParsed.warning,
      startRaw,
      startParsed.date
    );
  }

  if (startParsed.error) {
    addIssue(
      issues,
      base,
      'error',
      'unparseable_start_date',
      'start_date',
      startParsed.error,
      startRaw
    );
  }

  if (endParsed.warning) {
    addIssue(
      issues,
      base,
      'warning',
      'inferred_end_date',
      'end_date',
      endParsed.warning,
      endRaw,
      endParsed.date
    );
  }

  if (endParsed.error && clean(endRaw)) {
    addIssue(
      issues,
      base,
      'error',
      'unparseable_end_date',
      'end_date',
      endParsed.error,
      endRaw
    );
  }

  let startDate = startParsed.date;
  let endDate = endParsed.date;

  if (startDate && !endDate) {
    endDate = startDate;

    addIssue(
      issues,
      base,
      'warning',
      'end_date_defaulted_to_start_date',
      'end_date',
      'Missing end date defaulted to start date.',
      endRaw,
      endDate
    );
  }

  const split = splitAttendanceAndSponsoring(
    get('attendance_sponsoring_combined'),
    get('attendance_format'),
    get('sponsoring_level')
  );

  const title = clean(get('title'));
  const location = clean(get('location'));
  const entity = clean(get('entity'));

  const requirements = clean(get('requirements'));

  const rawRow = buildRawRow(row, currentHeaderRow);
  const extraFields = buildExtraFields(row, currentColumnMap, currentHeaderRow);

  if (requirements) {
    extraFields.requirements = requirements;
  }

  const normalizedPayload = {
    record_type: defaultRecordType,
    record_category: currentSection,
    record_subcategory: null,
    title,
    start_date: startDate,
    end_date: endDate,
    month,
    location,
    website: normalizeUrl(get('website')),
    entity,
    ga: parseBool(get('ga')),
    attendance_format: split.attendance_format,
    sponsoring_level: split.sponsoring_level,
    contact_person: clean(get('contact_person')),
    project_owner: clean(get('project_owner')),
    status: clean(get('status')) || 'Unknown',
  };

  const record = {
    record_id: `rec_${hash([importJobId, currentSection, sourceRowNumber, title, startDate].join('|'), 24)}`,
    import_job_id: importJobId,
    schema_version: schemaVersion,
    ...normalizedPayload,
    source_file_id: sourceFileId,
    source_file_name: sourceFileName,
    source_sheet: currentSection,
    source_row_number: sourceRowNumber,
    validation_status: 'valid',
    validation_notes: null,
    raw_row: rawRow,
    normalized_payload: normalizedPayload,
    extra_fields: extraFields,
  };

  const errors = [];

  if (!record.title) {
    errors.push({
      field: 'title',
      code: 'required_field_missing',
      message: 'title is required.',
    });
  }

  if (defaultRecordType === 'event' && !record.start_date) {
    errors.push({
      field: 'start_date',
      code: 'required_field_missing',
      message: 'start_date is required for event records.',
    });
  }

  if (record.start_date && record.end_date && record.end_date < record.start_date) {
    errors.push({
      field: 'end_date',
      code: 'end_date_before_start_date',
      message: 'end_date is before start_date.',
    });
  }

  const rowWarnings = issues
    .filter(issue =>
      issue.source_sheet === currentSection &&
      issue.source_row_number === sourceRowNumber &&
      issue.severity === 'warning'
    )
    .map(issue => issue.issue_code);

  if (errors.length) {
    record.validation_status = 'rejected';
    record.validation_notes = errors.map(e => e.message).join('; ');

    rejected_rows.push({
      import_job_id: importJobId,
      source_file_id: sourceFileId,
      source_file_name: sourceFileName,
      source_sheet: currentSection,
      source_row_number: sourceRowNumber,
      rejection_reason: record.validation_notes,
      errors,
      raw_row: rawRow,
    });

    for (const error of errors) {
      addIssue(
        issues,
        base,
        'error',
        error.code,
        error.field,
        error.message
      );
    }
  } else {
    if (rowWarnings.length) {
      record.validation_status = 'valid_with_warnings';
      record.validation_notes = rowWarnings.join('; ');
    }

    records.push(record);
  }
}

const warningCount = issues.filter(issue => issue.severity === 'warning').length;
const errorCount = issues.filter(issue => issue.severity === 'error').length;

const job = {
  import_job_id: importJobId,
  schema_version: schemaVersion,
  status:
    errorCount > 0 && records.length === 0
      ? 'failed_no_clean_records'
      : warningCount || errorCount
        ? 'completed_with_issues'
        : 'completed',
  source_system: 'google_drive_xlsx_extract_multi_section',
  source_file_id: sourceFileId,
  source_file_name: sourceFileName,
  record_type: defaultRecordType,
  inferred_year: inferredYear,
  total_records: records.length + rejected_rows.length,
  clean_record_count: records.length,
  rejected_row_count: rejected_rows.length,
  issue_count: issues.length,
  warning_count: warningCount,
  error_count: errorCount,
  processed_sections: [...new Set(records.map(record => record.source_sheet))],
};

return [
  {
    json: {
      job,
      records,
      rejected_rows,
      issues,
    },
  },
];
